// @archeon:file
// @glyph FNC:IpcChannels
// @intent Shared IPC channel constants — single source of truth for main<->renderer communication
// @chain @v1 NED:system.ready => SHP:react-electron => OUT:installed

// @archeon:section implementation
export const IPC = {
  // Filesystem
  FS_READ_DIR: 'fs:read-dir',
  FS_READ_FILE: 'fs:read-file',
  FS_WRITE_FILE: 'fs:write-file',
  FS_DELETE: 'fs:delete',
  FS_STAT: 'fs:stat',
  FS_MKDIR: 'fs:mkdir',
  FS_SELECT_DIRECTORY: 'fs:select-directory',
  FS_SELECT_FILE: 'fs:select-file',

  // GitHub
  GH_AUTH_STATUS: 'gh:auth-status',
  GH_SET_TOKEN: 'gh:set-token',
  GH_CLEAR_TOKEN: 'gh:clear-token',
  GH_LIST_REPOS: 'gh:list-repos',
  GH_GET_REPO: 'gh:get-repo',
  GH_CLONE_REPO: 'gh:clone-repo',
  GH_CREATE_REPO: 'gh:create-repo',

  // SSH Keys
  SSH_LIST_KEYS: 'ssh:list-keys',
  SSH_GENERATE_KEY: 'ssh:generate-key',
  SSH_DELETE_KEY: 'ssh:delete-key',
  SSH_GET_PUBLIC_KEY: 'ssh:get-public-key',
  SSH_ADD_TO_AGENT: 'ssh:add-to-agent',
  SSH_TEST_CONNECTION: 'ssh:test-connection',

  // App
  APP_GET_VERSION: 'app:get-version',
  APP_GET_PLATFORM: 'app:get-platform',
} as const;

export type IpcChannel = (typeof IPC)[keyof typeof IPC];
// @archeon:endsection

