// @archeon:file
// @glyph FNC:SharedTypes
// @intent Shared type definitions for IPC communication between main and renderer
// @chain @v1 NED:system.ready => SHP:react-electron => OUT:installed

// @archeon:section implementation

// --- Filesystem types ---
export interface FsEntry {
  name: string;
  path: string;
  isDirectory: boolean;
  isFile: boolean;
  size: number;
  modifiedAt: number;
}

export interface FsStatResult {
  exists: boolean;
  isDirectory: boolean;
  isFile: boolean;
  size: number;
  createdAt: number;
  modifiedAt: number;
}

// --- GitHub types ---
export interface GhAuthStatus {
  authenticated: boolean;
  username?: string;
  scopes?: string[];
}

export interface GhRepo {
  id: number;
  name: string;
  fullName: string;
  description: string | null;
  private: boolean;
  htmlUrl: string;
  cloneUrl: string;
  sshUrl: string;
  defaultBranch: string;
  updatedAt: string;
}

export interface GhCreateRepoOptions {
  name: string;
  description?: string;
  isPrivate?: boolean;
  autoInit?: boolean;
}

// --- SSH types ---
export interface SshKeyInfo {
  name: string;
  path: string;
  publicKeyPath: string;
  type: 'rsa' | 'ed25519' | 'ecdsa' | 'dsa' | string;
  fingerprint: string;
  createdAt: number;
}

export interface SshGenerateOptions {
  name: string;
  type: 'ed25519' | 'rsa';
  comment?: string;
  passphrase?: string;
}

export interface SshTestResult {
  success: boolean;
  host: string;
  message: string;
}

// --- IPC Result wrapper ---
export type IpcResult<T> =
  | { ok: true; data: T }
  | { ok: false; error: string };
// @archeon:endsection

