// @archeon:file
// @glyph SVC:ElectronMain
// @intent Electron main process entry — creates window, registers IPC handlers
// @chain @v1 NED:system.ready => SHP:react-electron => OUT:installed

// @archeon:section imports
import { app, BrowserWindow, ipcMain } from 'electron';
import path from 'node:path';
import { registerFsHandlers } from './ipc/fs-handlers.js';
import { registerGithubHandlers } from './ipc/github-handlers.js';
import { registerSshHandlers } from './ipc/ssh-handlers.js';
import { registerAppHandlers } from './ipc/app-handlers.js';
// @archeon:endsection

// @archeon:section implementation
const isDev = !app.isPackaged;

let mainWindow: BrowserWindow | null = null;

async function createWindow() {
  mainWindow = new BrowserWindow({
    width: 1200,
    height: 800,
    minWidth: 800,
    minHeight: 600,
    webPreferences: {
      preload: path.join(__dirname, '../preload/index.js'),
      contextIsolation: true,
      nodeIntegration: false,
      sandbox: true,
    },
    titleBarStyle: process.platform === 'darwin' ? 'hiddenInset' : 'default',
    show: false,
  });

  // Register all IPC handlers
  registerFsHandlers(ipcMain);
  registerGithubHandlers(ipcMain);
  registerSshHandlers(ipcMain);
  registerAppHandlers(ipcMain);

  // Graceful show
  mainWindow.on('ready-to-show', () => {
    mainWindow?.show();
  });

  mainWindow.on('closed', () => {
    mainWindow = null;
  });

  if (isDev) {
    mainWindow.loadURL('http://localhost:5173');
    mainWindow.webContents.openDevTools({ mode: 'detach' });
  } else {
    mainWindow.loadFile(path.join(__dirname, '../renderer/index.html'));
  }
}

app.whenReady().then(createWindow);

app.on('window-all-closed', () => {
  if (process.platform !== 'darwin') app.quit();
});

app.on('activate', () => {
  if (BrowserWindow.getAllWindows().length === 0) createWindow();
});
// @archeon:endsection

