// @glyph BRG:Preload
// @intent Secure IPC bridge — exposes whitelisted async methods to renderer via contextBridge
// @chain @v1 NED:system.ready => SHP:react-electron => OUT:installed

// @archeon:section imports
import { contextBridge, ipcRenderer } from 'electron';
import { IPC } from '../shared/ipc-channels.js';
import type {
  FsEntry, FsStatResult,
  GhAuthStatus, GhRepo, GhCreateRepoOptions,
  SshKeyInfo, SshGenerateOptions, SshTestResult,
  IpcResult
} from '../shared/types.js';
// @archeon:endsection

// @archeon:section implementation
const api = {
  // --- Filesystem ---
  fs: {
    readDir: (dirPath: string): Promise<IpcResult<FsEntry[]>> =>
      ipcRenderer.invoke(IPC.FS_READ_DIR, dirPath),
    readFile: (filePath: string, encoding?: string): Promise<IpcResult<string>> =>
      ipcRenderer.invoke(IPC.FS_READ_FILE, filePath, encoding),
    writeFile: (filePath: string, content: string): Promise<IpcResult<void>> =>
      ipcRenderer.invoke(IPC.FS_WRITE_FILE, filePath, content),
    delete: (targetPath: string): Promise<IpcResult<void>> =>
      ipcRenderer.invoke(IPC.FS_DELETE, targetPath),
    stat: (targetPath: string): Promise<IpcResult<FsStatResult>> =>
      ipcRenderer.invoke(IPC.FS_STAT, targetPath),
    mkdir: (dirPath: string): Promise<IpcResult<void>> =>
      ipcRenderer.invoke(IPC.FS_MKDIR, dirPath),
    selectDirectory: (): Promise<IpcResult<string | null>> =>
      ipcRenderer.invoke(IPC.FS_SELECT_DIRECTORY),
    selectFile: (filters?: { name: string; extensions: string[] }[]): Promise<IpcResult<string | null>> =>
      ipcRenderer.invoke(IPC.FS_SELECT_FILE, filters),
  },

  // --- GitHub ---
  github: {
    getAuthStatus: (): Promise<IpcResult<GhAuthStatus>> =>
      ipcRenderer.invoke(IPC.GH_AUTH_STATUS),
    setToken: (token: string): Promise<IpcResult<GhAuthStatus>> =>
      ipcRenderer.invoke(IPC.GH_SET_TOKEN, token),
    clearToken: (): Promise<IpcResult<void>> =>
      ipcRenderer.invoke(IPC.GH_CLEAR_TOKEN),
    listRepos: (page?: number, perPage?: number): Promise<IpcResult<GhRepo[]>> =>
      ipcRenderer.invoke(IPC.GH_LIST_REPOS, page, perPage),
    getRepo: (owner: string, repo: string): Promise<IpcResult<GhRepo>> =>
      ipcRenderer.invoke(IPC.GH_GET_REPO, owner, repo),
    cloneRepo: (url: string, destPath: string): Promise<IpcResult<string>> =>
      ipcRenderer.invoke(IPC.GH_CLONE_REPO, url, destPath),
    createRepo: (options: GhCreateRepoOptions): Promise<IpcResult<GhRepo>> =>
      ipcRenderer.invoke(IPC.GH_CREATE_REPO, options),
  },

  // --- SSH Keys ---
  ssh: {
    listKeys: (): Promise<IpcResult<SshKeyInfo[]>> =>
      ipcRenderer.invoke(IPC.SSH_LIST_KEYS),
    generateKey: (options: SshGenerateOptions): Promise<IpcResult<SshKeyInfo>> =>
      ipcRenderer.invoke(IPC.SSH_GENERATE_KEY, options),
    deleteKey: (keyPath: string): Promise<IpcResult<void>> =>
      ipcRenderer.invoke(IPC.SSH_DELETE_KEY, keyPath),
    getPublicKey: (keyPath: string): Promise<IpcResult<string>> =>
      ipcRenderer.invoke(IPC.SSH_GET_PUBLIC_KEY, keyPath),
    addToAgent: (keyPath: string): Promise<IpcResult<void>> =>
      ipcRenderer.invoke(IPC.SSH_ADD_TO_AGENT, keyPath),
    testConnection: (host: string): Promise<IpcResult<SshTestResult>> =>
      ipcRenderer.invoke(IPC.SSH_TEST_CONNECTION, host),
  },

  // --- App ---
  app: {
    getVersion: (): Promise<string> =>
      ipcRenderer.invoke(IPC.APP_GET_VERSION),
    getPlatform: (): Promise<string> =>
      ipcRenderer.invoke(IPC.APP_GET_PLATFORM),
  },
};

contextBridge.exposeInMainWorld('api', api);
// @archeon:endsection

