// @archeon:file
// @glyph SVC:FsHandlers
// @intent IPC handlers for filesystem operations — read, write, delete, stat, directory listing
// @chain @v1 NED:filesystem => SVC:FsHandlers => ADP:NodeFs => OUT:fs.result

// @archeon:section imports
import { type IpcMain, dialog } from 'electron';
import fs from 'node:fs/promises';
import path from 'node:path';
import { IPC } from '../../shared/ipc-channels.js';
import type { FsEntry, FsStatResult, IpcResult } from '../../shared/types.js';
// @archeon:endsection

// @archeon:section helpers
function ok<T>(data: T): IpcResult<T> {
  return { ok: true, data };
}

function err<T>(error: string): IpcResult<T> {
  return { ok: false, error };
}

function isPathSafe(targetPath: string): boolean {
  const resolved = path.resolve(targetPath);
  // Block traversal above home directory
  const home = process.env.HOME || process.env.USERPROFILE || '/';
  return resolved.startsWith(home);
}
// @archeon:endsection

// @archeon:section implementation
export function registerFsHandlers(ipcMain: IpcMain) {
  ipcMain.handle(IPC.FS_READ_DIR, async (_event, dirPath: string): Promise<IpcResult<FsEntry[]>> => {
    if (!isPathSafe(dirPath)) return err('Path not allowed');
    try {
      const entries = await fs.readdir(dirPath, { withFileTypes: true });
      const result: FsEntry[] = await Promise.all(
        entries.map(async (entry) => {
          const fullPath = path.join(dirPath, entry.name);
          const stat = await fs.stat(fullPath).catch(() => null);
          return {
            name: entry.name,
            path: fullPath,
            isDirectory: entry.isDirectory(),
            isFile: entry.isFile(),
            size: stat?.size ?? 0,
            modifiedAt: stat?.mtimeMs ?? 0,
          };
        })
      );
      return ok(result);
    } catch (e) {
      return err(`Failed to read directory: ${(e as Error).message}`);
    }
  });

  ipcMain.handle(IPC.FS_READ_FILE, async (_event, filePath: string, encoding = 'utf-8'): Promise<IpcResult<string>> => {
    if (!isPathSafe(filePath)) return err('Path not allowed');
    try {
      const content = await fs.readFile(filePath, { encoding: encoding as BufferEncoding });
      return ok(content);
    } catch (e) {
      return err(`Failed to read file: ${(e as Error).message}`);
    }
  });

  ipcMain.handle(IPC.FS_WRITE_FILE, async (_event, filePath: string, content: string): Promise<IpcResult<void>> => {
    if (!isPathSafe(filePath)) return err('Path not allowed');
    try {
      await fs.mkdir(path.dirname(filePath), { recursive: true });
      await fs.writeFile(filePath, content, 'utf-8');
      return ok(undefined);
    } catch (e) {
      return err(`Failed to write file: ${(e as Error).message}`);
    }
  });

  ipcMain.handle(IPC.FS_DELETE, async (_event, targetPath: string): Promise<IpcResult<void>> => {
    if (!isPathSafe(targetPath)) return err('Path not allowed');
    try {
      await fs.rm(targetPath, { recursive: true });
      return ok(undefined);
    } catch (e) {
      return err(`Failed to delete: ${(e as Error).message}`);
    }
  });

  ipcMain.handle(IPC.FS_STAT, async (_event, targetPath: string): Promise<IpcResult<FsStatResult>> => {
    if (!isPathSafe(targetPath)) return err('Path not allowed');
    try {
      const stat = await fs.stat(targetPath);
      return ok({
        exists: true,
        isDirectory: stat.isDirectory(),
        isFile: stat.isFile(),
        size: stat.size,
        createdAt: stat.birthtimeMs,
        modifiedAt: stat.mtimeMs,
      });
    } catch {
      return ok({ exists: false, isDirectory: false, isFile: false, size: 0, createdAt: 0, modifiedAt: 0 });
    }
  });

  ipcMain.handle(IPC.FS_MKDIR, async (_event, dirPath: string): Promise<IpcResult<void>> => {
    if (!isPathSafe(dirPath)) return err('Path not allowed');
    try {
      await fs.mkdir(dirPath, { recursive: true });
      return ok(undefined);
    } catch (e) {
      return err(`Failed to create directory: ${(e as Error).message}`);
    }
  });

  ipcMain.handle(IPC.FS_SELECT_DIRECTORY, async (): Promise<IpcResult<string | null>> => {
    const result = await dialog.showOpenDialog({ properties: ['openDirectory', 'createDirectory'] });
    return ok(result.canceled ? null : result.filePaths[0]);
  });

  ipcMain.handle(IPC.FS_SELECT_FILE, async (_event, filters?: { name: string; extensions: string[] }[]): Promise<IpcResult<string | null>> => {
    const result = await dialog.showOpenDialog({
      properties: ['openFile'],
      filters: filters ?? [{ name: 'All Files', extensions: ['*'] }],
    });
    return ok(result.canceled ? null : result.filePaths[0]);
  });
}
// @archeon:endsection

