// @archeon:file
// @glyph SVC:GithubHandlers
// @intent IPC handlers for GitHub API — auth, repos, clone via Octokit
// @chain @v1 NED:github => SVC:GithubHandlers => ADP:Octokit => OUT:gh.result

// @archeon:section imports
import { type IpcMain } from 'electron';
import { safeStorage } from 'electron';
import { Octokit } from '@octokit/rest';
import { execFile } from 'node:child_process';
import { promisify } from 'node:util';
import { IPC } from '../../shared/ipc-channels.js';
import type { GhAuthStatus, GhRepo, GhCreateRepoOptions, IpcResult } from '../../shared/types.js';
// @archeon:endsection

// @archeon:section helpers
const execFileAsync = promisify(execFile);
const TOKEN_KEY = 'github-token';

let octokit: Octokit | null = null;
let encryptedToken: Buffer | null = null;

function ok<T>(data: T): IpcResult<T> {
  return { ok: true, data };
}

function err<T>(error: string): IpcResult<T> {
  return { ok: false, error };
}

function getToken(): string | null {
  if (!encryptedToken) return null;
  return safeStorage.decryptString(encryptedToken);
}

function mapRepo(repo: any): GhRepo {
  return {
    id: repo.id,
    name: repo.name,
    fullName: repo.full_name,
    description: repo.description,
    private: repo.private,
    htmlUrl: repo.html_url,
    cloneUrl: repo.clone_url,
    sshUrl: repo.ssh_url,
    defaultBranch: repo.default_branch,
    updatedAt: repo.updated_at,
  };
}
// @archeon:endsection

// @archeon:section implementation
export function registerGithubHandlers(ipcMain: IpcMain) {
  ipcMain.handle(IPC.GH_AUTH_STATUS, async (): Promise<IpcResult<GhAuthStatus>> => {
    try {
      const token = getToken();
      if (!token) return ok({ authenticated: false });
      const client = new Octokit({ auth: token });
      const { data: user } = await client.users.getAuthenticated();
      return ok({ authenticated: true, username: user.login });
    } catch {
      return ok({ authenticated: false });
    }
  });

  ipcMain.handle(IPC.GH_SET_TOKEN, async (_event, token: string): Promise<IpcResult<GhAuthStatus>> => {
    try {
      if (!safeStorage.isEncryptionAvailable()) return err('Encryption not available on this system');
      // Validate token first
      const client = new Octokit({ auth: token });
      const { data: user } = await client.users.getAuthenticated();
      // Store encrypted
      encryptedToken = safeStorage.encryptString(token);
      octokit = client;
      return ok({ authenticated: true, username: user.login });
    } catch {
      return err('Invalid GitHub token');
    }
  });

  ipcMain.handle(IPC.GH_CLEAR_TOKEN, async (): Promise<IpcResult<void>> => {
    encryptedToken = null;
    octokit = null;
    return ok(undefined);
  });

  ipcMain.handle(IPC.GH_LIST_REPOS, async (_event, page = 1, perPage = 30): Promise<IpcResult<GhRepo[]>> => {
    try {
      const token = getToken();
      if (!token) return err('Not authenticated');
      const client = new Octokit({ auth: token });
      const { data } = await client.repos.listForAuthenticatedUser({
        page,
        per_page: perPage,
        sort: 'updated',
      });
      return ok(data.map(mapRepo));
    } catch (e) {
      return err(`Failed to list repos: ${(e as Error).message}`);
    }
  });

  ipcMain.handle(IPC.GH_GET_REPO, async (_event, owner: string, repo: string): Promise<IpcResult<GhRepo>> => {
    try {
      const token = getToken();
      if (!token) return err('Not authenticated');
      const client = new Octokit({ auth: token });
      const { data } = await client.repos.get({ owner, repo });
      return ok(mapRepo(data));
    } catch (e) {
      return err(`Failed to get repo: ${(e as Error).message}`);
    }
  });

  ipcMain.handle(IPC.GH_CLONE_REPO, async (_event, url: string, destPath: string): Promise<IpcResult<string>> => {
    try {
      await execFileAsync('git', ['clone', url, destPath]);
      return ok(destPath);
    } catch (e) {
      return err(`Failed to clone: ${(e as Error).message}`);
    }
  });

  ipcMain.handle(IPC.GH_CREATE_REPO, async (_event, options: GhCreateRepoOptions): Promise<IpcResult<GhRepo>> => {
    try {
      const token = getToken();
      if (!token) return err('Not authenticated');
      const client = new Octokit({ auth: token });
      const { data } = await client.repos.createForAuthenticatedUser({
        name: options.name,
        description: options.description,
        private: options.isPrivate ?? true,
        auto_init: options.autoInit ?? false,
      });
      return ok(mapRepo(data));
    } catch (e) {
      return err(`Failed to create repo: ${(e as Error).message}`);
    }
  });
}
// @archeon:endsection

