// @archeon:file
// @glyph SVC:SshHandlers
// @intent IPC handlers for SSH key management — list, generate, delete, test connection
// @chain @v1 NED:ssh => SVC:SshHandlers => ADP:SshAdapter => OUT:ssh.result

// @archeon:section imports
import { type IpcMain } from 'electron';
import fs from 'node:fs/promises';
import path from 'node:path';
import os from 'node:os';
import { execFile } from 'node:child_process';
import { promisify } from 'node:util';
import { IPC } from '../../shared/ipc-channels.js';
import type { SshKeyInfo, SshGenerateOptions, SshTestResult, IpcResult } from '../../shared/types.js';
// @archeon:endsection

// @archeon:section helpers
const execFileAsync = promisify(execFile);

function ok<T>(data: T): IpcResult<T> {
  return { ok: true, data };
}

function err<T>(error: string): IpcResult<T> {
  return { ok: false, error };
}

function getSshDir(): string {
  return path.join(os.homedir(), '.ssh');
}

async function getKeyFingerprint(pubKeyPath: string): Promise<string> {
  try {
    const { stdout } = await execFileAsync('ssh-keygen', ['-lf', pubKeyPath]);
    return stdout.trim().split(' ')[1] || 'unknown';
  } catch {
    return 'unknown';
  }
}

async function detectKeyType(pubKeyPath: string): Promise<string> {
  try {
    const content = await fs.readFile(pubKeyPath, 'utf-8');
    if (content.includes('ssh-ed25519')) return 'ed25519';
    if (content.includes('ssh-rsa')) return 'rsa';
    if (content.includes('ecdsa')) return 'ecdsa';
    if (content.includes('ssh-dss')) return 'dsa';
    return 'unknown';
  } catch {
    return 'unknown';
  }
}
// @archeon:endsection

// @archeon:section implementation
export function registerSshHandlers(ipcMain: IpcMain) {
  ipcMain.handle(IPC.SSH_LIST_KEYS, async (): Promise<IpcResult<SshKeyInfo[]>> => {
    try {
      const sshDir = getSshDir();
      await fs.mkdir(sshDir, { recursive: true, mode: 0o700 });
      const entries = await fs.readdir(sshDir);
      const pubFiles = entries.filter((f) => f.endsWith('.pub'));

      const keys: SshKeyInfo[] = await Promise.all(
        pubFiles.map(async (pubFile) => {
          const pubPath = path.join(sshDir, pubFile);
          const privPath = pubPath.replace(/\.pub$/, '');
          const stat = await fs.stat(pubPath).catch(() => null);
          return {
            name: pubFile.replace(/\.pub$/, ''),
            path: privPath,
            publicKeyPath: pubPath,
            type: await detectKeyType(pubPath),
            fingerprint: await getKeyFingerprint(pubPath),
            createdAt: stat?.birthtimeMs ?? 0,
          };
        })
      );
      return ok(keys);
    } catch (e) {
      return err(`Failed to list SSH keys: ${(e as Error).message}`);
    }
  });

  ipcMain.handle(IPC.SSH_GENERATE_KEY, async (_event, options: SshGenerateOptions): Promise<IpcResult<SshKeyInfo>> => {
    try {
      const sshDir = getSshDir();
      await fs.mkdir(sshDir, { recursive: true, mode: 0o700 });
      const keyPath = path.join(sshDir, options.name);

      // Prevent overwriting
      try {
        await fs.access(keyPath);
        return err(`Key '${options.name}' already exists`);
      } catch {
        // File doesn't exist — good
      }

      const args = [
        '-t', options.type,
        '-f', keyPath,
        '-C', options.comment || `${options.name}@electron-app`,
        '-N', options.passphrase || '',
      ];

      await execFileAsync('ssh-keygen', args);

      const pubPath = `${keyPath}.pub`;
      const stat = await fs.stat(pubPath);
      return ok({
        name: options.name,
        path: keyPath,
        publicKeyPath: pubPath,
        type: options.type,
        fingerprint: await getKeyFingerprint(pubPath),
        createdAt: stat.birthtimeMs,
      });
    } catch (e) {
      return err(`Failed to generate key: ${(e as Error).message}`);
    }
  });

  ipcMain.handle(IPC.SSH_DELETE_KEY, async (_event, keyPath: string): Promise<IpcResult<void>> => {
    try {
      const sshDir = getSshDir();
      const resolved = path.resolve(keyPath);
      if (!resolved.startsWith(sshDir)) return err('Can only delete keys in ~/.ssh');
      await fs.rm(resolved);
      await fs.rm(`${resolved}.pub`).catch(() => {});
      return ok(undefined);
    } catch (e) {
      return err(`Failed to delete key: ${(e as Error).message}`);
    }
  });

  ipcMain.handle(IPC.SSH_GET_PUBLIC_KEY, async (_event, keyPath: string): Promise<IpcResult<string>> => {
    try {
      const pubPath = keyPath.endsWith('.pub') ? keyPath : `${keyPath}.pub`;
      const sshDir = getSshDir();
      const resolved = path.resolve(pubPath);
      if (!resolved.startsWith(sshDir)) return err('Can only read keys in ~/.ssh');
      const content = await fs.readFile(resolved, 'utf-8');
      return ok(content.trim());
    } catch (e) {
      return err(`Failed to read public key: ${(e as Error).message}`);
    }
  });

  ipcMain.handle(IPC.SSH_ADD_TO_AGENT, async (_event, keyPath: string): Promise<IpcResult<void>> => {
    try {
      await execFileAsync('ssh-add', [keyPath]);
      return ok(undefined);
    } catch (e) {
      return err(`Failed to add key to agent: ${(e as Error).message}`);
    }
  });

  ipcMain.handle(IPC.SSH_TEST_CONNECTION, async (_event, host: string): Promise<IpcResult<SshTestResult>> => {
    try {
      const { stdout, stderr } = await execFileAsync('ssh', ['-T', '-o', 'StrictHostKeyChecking=accept-new', `git@${host}`], {
        timeout: 10000,
      }).catch((e) => ({ stdout: e.stdout || '', stderr: e.stderr || '' }));
      const output = stdout + stderr;
      const success = output.toLowerCase().includes('successfully authenticated');
      return ok({ success, host, message: output.trim() });
    } catch (e) {
      return ok({ success: false, host, message: (e as Error).message });
    }
  });
}
// @archeon:endsection

