// @archeon:file
// @glyph CMP:App
// @intent Root shell component — layout, routing placeholder
// @chain @v1 NED:system.ready => CMP:App => OUT:ui.ready

// @archeon:section imports
import { useState, useEffect } from 'react';
// @archeon:endsection

// @archeon:section component
export default function App() {
  const [platform, setPlatform] = useState<string>('');
  const [version, setVersion] = useState<string>('');

  useEffect(() => {
    window.api.app.getPlatform().then(setPlatform);
    window.api.app.getVersion().then(setVersion);
  }, []);

  return (
    <div className="flex flex-col items-center justify-center min-h-screen p-6 bg-zinc-950 text-zinc-100">
      <h1 className="text-3xl font-bold mb-2">Electron + React + Vite</h1>
      <p className="text-zinc-400 mb-6">Edit <code className="text-emerald-400">src/renderer/App.tsx</code> to get started</p>
      <div className="flex gap-4 text-sm text-zinc-500">
        <span>Platform: {platform}</span>
        <span>v{version}</span>
      </div>
    </div>
  );
}
